mapper.select:
SELECT c.id, c.title, c.type, s.name AS creatorName, c.payee_name AS payeeName, c.account, c.amount, c.info, c.verify_state AS verifyState, c.verify_remark AS verifyRemark, c.add_time AS addTime FROM cashout c LEFT JOIN staff s ON c.creator = s.id AND s.deleted = 0 WHERE c.deleted = 0
AND c.title LIKE CONCAT('%', #{q.title}, '%')
AND c.type = #{q.type}
AND c.verify_state = #{q.verifyState}
AND c.creator = #{q.creator}
AND c.payee_name LIKE CONCAT('%', #{q.payeeName}, '%')
AND c.add_time >= CONCAT(#{q.startDate}, ' 00:00:00')
AND c.add_time <= CONCAT(#{q.endDate}, ' 23:59:59')
ORDER BY c.add_time DESC
